import "./MyRecipe.css";
import { Link } from "react-router-dom";
import UserNavbar from "./UserNavbar";

export default function MyRecipes() {
  // Dummy user recipes (replace with backend API later)
  const myRecipes = [
    {
      id: 1,
      title: "Spaghetti Carbonara",
      views: 1200,
      image: "https://images.unsplash.com/photo-1504674900247-0877df9cc836",
    },
    {
      id: 2,
      title: "Grilled Chicken Salad",
      views: 850,
      image: "https://images.unsplash.com/photo-1604908177522-402dbf6cddc",
    },
  ];

  const handleDelete = (id) => {
    // Later: call delete API
    alert(`Recipe with ID ${id} deleted (UI only)`);
  };

  return (
    <>
      {/* USER NAVBAR */}
      <UserNavbar />

      {/* MY RECIPES PAGE */}
      <div className="my-recipes-page">
        <h2>My Recipes</h2>

        {myRecipes.length === 0 ? (
          <p className="no-recipes">You have not added any recipes yet.</p>
        ) : (
          <div className="recipes-grid">
            {myRecipes.map((recipe) => (
              <div className="recipe-card" key={recipe.id}>
                <img src={recipe.image} alt={recipe.title} />

                <div className="recipe-info">
                  <h3>{recipe.title}</h3>
                  <p>👁 {recipe.views} views</p>

                  <div className="action-buttons">
                    <Link
                      to={`/edit-recipe/${recipe.id}`}
                      className="edit-btn"
                    >
                      Edit
                    </Link>

                    <button
                      className="delete-btn"
                      onClick={() => handleDelete(recipe.id)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </>
  );
}
